DROP TABLE IF EXISTS `configuraciones_turnos`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `configuraciones_turnos` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tipo` enum('ROTATIVO','FIJO') COLLATE utf8mb4_unicode_ci NOT NULL,
  `nombre_configuracion` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `area_id` int NOT NULL,
  `jefe_id` int NOT NULL,
  `turno_id` int DEFAULT NULL,
  `empleados_ids` json NOT NULL,
  `configuracion` json NOT NULL,
  `fecha_inicio` date DEFAULT NULL,
  `fecha_fin` date DEFAULT NULL,
  `dias_descanso` json DEFAULT NULL,
  `activo` tinyint(1) NOT NULL DEFAULT '1',
  `creado_por` int DEFAULT NULL,
  `creado_en` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `actualizado_en` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `eliminado_en` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `fk_config_jefe` (`jefe_id`),
  KEY `fk_config_turno` (`turno_id`),
  KEY `fk_config_creado_por` (`creado_por`),
  KEY `idx_config_tipo` (`tipo`),
  KEY `idx_config_area` (`area_id`),
  KEY `idx_config_activo` (`activo`),
  CONSTRAINT `fk_config_area` FOREIGN KEY (`area_id`) REFERENCES `areas` (`id`),
  CONSTRAINT `fk_config_creado_por` FOREIGN KEY (`creado_por`) REFERENCES `usuarios_sistema` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_config_jefe` FOREIGN KEY (`jefe_id`) REFERENCES `empleados` (`id`),
  CONSTRAINT `fk_config_turno` FOREIGN KEY (`turno_id`) REFERENCES `turnos` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

