--
-- Table structure for table `registros_asistencia`
--

DROP TABLE IF EXISTS `registros_asistencia`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `registros_asistencia` (
  `id` int NOT NULL AUTO_INCREMENT,
  `empleado_id` int DEFAULT NULL,
  `tipo_evento` enum('ENTRADA','SALIDA') COLLATE utf8mb4_unicode_ci NOT NULL,
  `fecha_hora` datetime NOT NULL,
  `dispositivo_ip` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `codigo_evento` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `origen` enum('BIOMETRICO','MANUAL','IMPORTADO') COLLATE utf8mb4_unicode_ci DEFAULT 'BIOMETRICO',
  `procesado` tinyint(1) NOT NULL DEFAULT '0',
  `creado_en` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `fk_registro_emp` (`empleado_id`),
  KEY `idx_evento_fecha` (`tipo_evento`,`fecha_hora`),
  CONSTRAINT `fk_registro_emp` FOREIGN KEY (`empleado_id`) REFERENCES `empleados` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=37681 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

